local CATS={{name='Fuel',items={'Coal','Oil Barrel','Fuel Canister','Biofuel'}},{name='Wood',items={'Log','Sapling','Chair'}},{name='Scrap',items={'Broken Fan','Sheet Metal','Bolt','Metal Chair','Broken Microwave','Old Car Engine','Old Radio','Washing Machine','Cultist Gem','Tire','Gem of the Forest Fragment','UFO Junk','UFO Component'}},{name='Food',items={'Morsel','Cooked Morsel','Steak','Cooked Steak','Berry','Carrot','Cake','Chili','Stew'}},{name='Tool',items={'Old Flashlight','Strong Flashlight','Good Axe','Strong Axe','Chainsaw','Good Sack','Giant Sack','Kunai','Morningstar','Wildfire','Infernal Sack','Defense Blueprint','Bear Trap Blueprint','Lava Mine Blueprint','Medkit','Bandage','Spear','Poison Spear','Thorn Body','Obsidiron Body','Obsidiron Hammer','Obsidiron Boots','Cultist King Mace'}},{name='Gun',items={'Revolver','Revolver Ammo','Rifle','Rifle Ammo','Tactical Shotgun','Raygun','Laser Canon','Crossbow','Infernal Crossbow','Leather Body','Iron Body','Alien Armor'}}}
for _,cat in ipairs(CATS) do BringLeft:AddLabel(cat.name) for _,item in ipairs(cat.items) do local i='NTTBring_'..item:gsub('%W','_') bringSel[item]=false BringLeft:AddToggle(i,{Text=item,Default=false,Callback=function(v) bringSel[item]=v end}) end BringLeft:AddDivider() end
